using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change #1: discriminator property renamed from
            // "Discriminator" to "$type". Existing 500K documents and direct SQL
            // queries (e.g. WHERE c.Discriminator = 'Product') rely on the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change #2: the synthesized JSON "id" no longer
            // includes the discriminator prefix.  EF 8 wrote "Product|123"; EF 9
            // writes just "123".  Preserve the old format so lookups against
            // existing documents continue to work.
            entity.HasDiscriminatorInJsonId();

            // EF Core 9 breaking change #3: HasIndex now throws
            // InvalidOperationException for the Cosmos provider (indexes are
            // managed through Cosmos DB indexing policy, not EF).
            // ❌ entity.HasIndex(p => p.Sku);  — removed
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = null!;
}

