using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 breaking change #4: synchronous APIs (ToList, First, Single, …)
    // now throw InvalidOperationException on the Cosmos provider. All queries must
    // use their async counterparts.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator, which works because
        // we kept the old property name via HasDiscriminator<string>("Discriminator").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

